#!/usr/bin/env bash
set -e

HERMES_HOME="${HERMES_HOME:-/opt/data}"
PROFILE_CONFIG="/opt/hermes/profiles/default/config.yaml"
VOLUME_CONFIG="$HERMES_HOME/config.yaml"
VERSION="v15"

if [ -f "$PROFILE_CONFIG" ] && grep -q "CONFIG_VERSION: $VERSION" "$PROFILE_CONFIG" 2>/dev/null; then
    echo "[04-config-gen] Config v15 exists, skipping"
    exit 0
fi

echo "[04-config-gen] Generating config.yaml..."

mkdir -p "$(dirname "$PROFILE_CONFIG")"
mkdir -p "$(dirname "$VOLUME_CONFIG")"

TEMP_CONFIG=$(mktemp)
cat > "$TEMP_CONFIG" << 'YAMLEOF'
# Generated by Railway startup — v15
# CONFIG_VERSION: v15

timezone: America/Chicago

gateway:
  model: deepseek/deepseek-v4-pro
  provider: openrouter

platforms: {}

mcp_servers:
  gbrain:
    command: gbrain
    args:
      - mcp
      - --source
      - default
    transport: stdio
    enabled: true

  slack:
    command: npx
    args:
      - "-y"
      - "@anthropic/mcp-server-slack"
    enabled: false
    env:
      SLACK_BOT_TOKEN: ""
      SLACK_TEAM_ID: ""

  atlassian:
    command: npx
    args:
      - "-y"
      - "@anthropic/mcp-server-atlassian"
    enabled: false
    env:
      ATLASSIAN_API_TOKEN: ""
      ATLASSIAN_DOMAIN: "bookmarked-team.atlassian.net"
      ATLASSIAN_EMAIL: "steve@bookmarked.com"

  hubspot:
    command: npx
    args:
      - "-y"
      - "@anthropic/mcp-server-hubspot"
    enabled: false
    env:
      HUBSPOT_API_KEY: ""

auxiliary:
  vision:
    provider: openrouter
    model: google/gemini-2.5-flash

GATEWAY_ALLOW_ALL_USERS: "true"
HERMES_DASHBOARD: "1"
YAMLEOF

cp "$TEMP_CONFIG" "$PROFILE_CONFIG"
cp "$TEMP_CONFIG" "$VOLUME_CONFIG"
rm -f "$TEMP_CONFIG"

echo "[04-config-gen] Config written to $PROFILE_CONFIG and $VOLUME_CONFIG"

# Remove stale basic auth .env if it exists
rm -f /root/.hermes/.env
# OAuth is used — no .env needed. The provider activates from HERMES_DASHBOARD_OAUTH_CLIENT_ID env var.
echo "[04-config-gen] OAuth enabled via env var"